"use strict";import utils from"../utils.js";function trimSPorHTAB(e){let t=0,r=e.length;for(;t<r;){const r=e.charCodeAt(t);if(9!==r&&32!==r)break;t+=1}for(;r>t;){const t=e.charCodeAt(r-1);if(9!==t&&32!==t)break;r-=1}return 0===t&&r===e.length?e:e.slice(t,r)}const INVALID_UNICODE_HEADER_VALUE_CHARS=new RegExp("[\\u0000-\\u0008\\u000a-\\u001f\\u007f]+","g"),INVALID_BYTE_STRING_HEADER_VALUE_CHARS=new RegExp("[^\\u0009\\u0020-\\u007e\\u0080-\\u00ff]+","g");function sanitizeValue(e,t){return utils.isArray(e)?e.map(e=>sanitizeValue(e,t)):trimSPorHTAB(String(e).replace(t,""))}export const sanitizeHeaderValue=e=>sanitizeValue(e,INVALID_UNICODE_HEADER_VALUE_CHARS);export const sanitizeByteStringHeaderValue=e=>sanitizeValue(e,INVALID_BYTE_STRING_HEADER_VALUE_CHARS);export function toByteStringHeaderObject(e){const t=Object.create(null);return utils.forEach(e.toJSON(),(e,r)=>{t[r]=sanitizeByteStringHeaderValue(e)}),t}